  3→import { describe, expect, it, vi } from 'vitest';
  4→import type { DropdownAction, DropdownSection } from './actions_dropdown';
  5→import { ActionsDropdown } from './actions_dropdown';
  6→
  7→function createActions(): DropdownAction[] {
  8→  return [
  9→    {
 10→      label: 'Copy URL',
 11→      shortcut: <span>⌘C</span>,
 12→      onClick: vi.fn(),
 13→    },
 14→    {
 15→      label: 'Delete',
 16→      shortcut: <span>⌘D</span>,
 17→      onClick: vi.fn(),
 18→    },
 19→    {
 20→      label: 'Move',
 21→      onClick: vi.fn(),
 22→    },
 23→  ];
 24→}
 25→
 26→function renderDropdown(
 27→  overrides: {
 28→    sections?: DropdownSection[];
 29→    open?: boolean;
 30→    onClose?: () => void;
 31→  } = {},
 32→) {
 33→  const actions = createActions();
 34→  const defaultSections: DropdownSection[] = [{ actions }];
 35→  const sections = overrides.sections ?? defaultSections;
 36→  const flatActions = sections.flatMap(s => s.actions);
 37→  const onClose = overrides.onClose ?? vi.fn();
 38→  const result = render(
 39→    <ActionsDropdown
 40→      sections={sections}
 41→      open={overrides.open ?? true}
 42→      onClose={onClose}
 43→    />,
 44→  );
 45→  return {
 46→    ...result,
 47→    actions: flatActions,
 48→    onClose,
 49→  };
 50→}
 51→
