295→interface ColorPickerViewProps {
296→  colors: ColorItemData[];
297→  onActiveIndexChange: (index: number) => void;
298→  onAction: (index: number) => void;
299→}
300→
301→function ColorPickerView({
302→  colors,
303→  onActiveIndexChange,
304→  onAction,
305→}: ColorPickerViewProps) {
306→  if (colors.length === 0) {
307→    return (
308→      <EmptyState
309→        icon={<SearchIcon />}
