353→export function App() {
354→  const [query, setQuery] = useState('');
355→  const [selectedIndex, setSelectedIndex] = useState(0);
356→  const [actionsOpen, setActionsOpen] = useState(false);
357→  const { toasts, show: showToast, hide: hideToast } = useToast();
358→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
359→  const nav = useNavigationStack<NavViewData>('Raycast');
360→  const { push, pop } = nav;
361→
362→  const viewType = nav.currentEntry?.data.type ?? 'root';
363→
364→  useEffect(() => {
365→    if (nav.stackDepth === 0) {
366→      setQuery('');
367→      setSelectedIndex(0);
368→      setActionsOpen(false);
369→    }
370→  }, [nav.stackDepth]);
371→
372→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
373→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
374→  const filteredColors = useMemo(
375→    () => filterColors(MOCK_COLORS, query),
376→    [query],
377→  );
378→
379→  const selectedItem =
380→    viewType === 'root' ? allItems[selectedIndex] : undefined;
381→
382→  const handleQueryChange = useCallback((value: string) => {
383→    setQuery(value);
384→    setSelectedIndex(0);
385→    setActionsOpen(false);
