434→    if (!item) return;
435→
436→    setActionsOpen(false);
437→
438→    if (item.id === 'color-picker') {
439→      push('Color Picker', { type: 'grid' });
440→      setQuery('');
441→      setSelectedIndex(0);
442→      showToast({
443→        style: 'success',
444→        title: 'Opened Color Picker',
