453→        style: 'success',
454→        title: `Opened ${item.title}`,
455→      });
456→    } else {
457→      showToast({
458→        style: 'success',
459→        title: `Opened ${item.title}`,
460→      });
461→    }
462→  }, [
463→    allItems,
464→    selectedIndex,
465→    showToast,
466→    push,
467→  ]);
468→
469→  const handleOpenCreateSnippet = useCallback(() => {
470→    setActionsOpen(false);
471→    push('Create Snippet', { type: 'form' });
472→    setQuery('');
473→    setSelectedIndex(0);
474→  }, [push]);
475→
476→  const toggleActions = useCallback(() => {
477→    setActionsOpen(prev => !prev);
478→  }, []);
479→
480→  const closeActions = useCallback(() => {
481→    setActionsOpen(false);
482→  }, []);
483→
484→  useEffect(() => {
485→    function handleKeyDown(e: KeyboardEvent) {
486→      if (e.key === 'k' && e.metaKey && viewType !== 'form') {
487→        e.preventDefault();
488→        setActionsOpen(prev => !prev);
489→        return;
490→      }
491→      if (e.key === 'n' && e.metaKey && viewType === 'root') {
492→        e.preventDefault();
493→        handleOpenCreateSnippet();
494→      }
495→    }
496→
497→    window.addEventListener('keydown', handleKeyDown);
498→    return () => window.removeEventListener('keydown', handleKeyDown);
499→  }, [
500→    viewType,
